-- build_bank.lua -- Generate a C metadata bank from the global SQLite form DB.
--
-- This consumes build/stencil_bank/stencil_bank.sqlite from build_stencils.sh
-- and emits libsponbank.so exposing the sponbank.h descriptor/selector API.
-- Native stencil rows carry raw byte bodies plus explicit data/control relocs.

package.path = "../../../?.lua;../../../?/init.lua;src/?.lua;src/?/init.lua;" .. package.path

local cjson = require("cjson")
local sqlite3 = require("lsqlite3")
local Util = require("src.util")
local Constants = require("experiments.lua_interpreter_vm.src.constants")

local M = {}

local U32 = 4294967296

local function q(s) return Util.shell_quote(s) end

local function mkdir_p(path) assert(Util.mkdir_p(path), "mkdir failed: " .. tostring(path)) end

local function c_string(s)
  s = tostring(s or "")
  s = s:gsub("\\", "\\\\"):gsub('"', '\\"'):gsub("\n", "\\n"):gsub("\r", "\\r"):gsub("\t", "\\t")
  return '"' .. s .. '"'
end

local function as_c_u64_literal(x)
  if type(x) == "string" and x:match("^0x[%x]+ULL$") then return x end
  if type(x) == "string" and x:match("^0x[%x]+$") then return x .. "ULL" end
  return "0x0000000000000000ULL"
end

local function parse_sig_lohi(lit)
  local hex = tostring(lit or "0"):match("^0x([%x]+)ULL$") or tostring(lit or "0"):match("^0x([%x]+)$") or "0"
  hex = hex:lower()
  if #hex > 16 then hex = hex:sub(#hex - 15) end
  hex = string.rep("0", 16 - #hex) .. hex
  return tonumber(hex:sub(9, 16), 16) or 0, tonumber(hex:sub(1, 8), 16) or 0
end

local function popcount32(x)
  x = tonumber(x) or 0
  local n = 0
  while x > 0 do
    if x % 2 >= 1 then n = n + 1 end
    x = math.floor(x / 2)
  end
  return n
end

local function sig_pop(lit)
  local lo, hi = parse_sig_lohi(lit)
  return popcount32(lo) + popcount32(hi)
end

local OPCODE = {}
for name, value in pairs(Constants.Op or {}) do
  if type(name) == "string" and type(value) == "number" then OPCODE[name] = value end
end

local function op_name(op)
  if type(op) == "table" then return tostring(op.op or "") end
  return tostring(op or "")
end

local function packed_pattern(ops)
  local packed = 0
  for i, op in ipairs(ops or {}) do
    if i > 4 then break end
    local code = OPCODE[op_name(op)] or 0
    packed = packed + code * (256 ^ (i - 1))
  end
  return packed
end

local function selector_key_num(ops)
  local len = #(ops or {})
  return len * U32 + packed_pattern(ops)
end

local function selector_key_lit(ops)
  local len = #(ops or {})
  return string.format("0x%x%08xULL", len, packed_pattern(ops))
end

local function chunk_path(bank_src, name)
  if name:sub(1, 1) == "/" then return name end
  return bank_src .. "/" .. name
end

local function open_inc(out_dir, prefix, suffix)
  local path = string.format("%s/%s_%s.inc", out_dir, prefix, suffix)
  local f = assert(io.open(path, "wb"))
  return f, path
end

local function write_array_header(c, ctype, name, dummy)
  c:write("const ", ctype, " ", name, "[] = {\n")
  if dummy then c:write("  ", dummy, "\n") end
end

local function write_include(c, path)
  c:write('#include "', Util.basename(path), '"\n')
end

local function write_array_footer(c)
  c:write("};\n\n")
end

local function hex_to_bytes(hex)
  if type(hex) ~= "string" then return {} end
  local out = {}
  for pair in hex:gmatch("%x%x") do out[#out + 1] = tonumber(pair, 16) or 0 end
  return out
end

local function u(v) return tonumber(v) or 0 end
local function field(obj, name, default) local v = obj and obj[name]; if v == nil then return default end; return v end

local function emit_index(out_dir, shards, patterns, l0, total_stencils)
  local pattern_keys = {}
  for k, _ in pairs(patterns) do pattern_keys[#pattern_keys + 1] = k end
  table.sort(pattern_keys)

  local c_path = out_dir .. "/bank_index.c"
  local c = assert(io.open(c_path, "wb"))
  c:write("/* Generated by src/build_bank.lua. Native stencil bank index. */\n")
  c:write('#include "sponbank.h"\n#include <stddef.h>\n#include <stdint.h>\n\n')

  for _, s in ipairs(shards) do
    local i = s.chunk
    c:write(string.format("extern const SponStencilDesc spon_chunk_%d_stencils[];\n", i))
    c:write(string.format("extern const unsigned char spon_chunk_%d_data[];\n", i))
    c:write(string.format("extern const SponEndpointDesc spon_chunk_%d_endpoints[];\n", i))
    c:write(string.format("extern const SponLocationDesc spon_chunk_%d_locations[];\n", i))
    c:write(string.format("extern const SponDataReloc spon_chunk_%d_data_relocs[];\n", i))
    c:write(string.format("extern const SponControlReloc spon_chunk_%d_control_relocs[];\n", i))
    c:write(string.format("extern const SponSlotMapEntry spon_chunk_%d_slotmaps[];\n", i))
    c:write(string.format("extern const SponProjectionEntry spon_chunk_%d_projections[];\n", i))
    c:write(string.format("extern const SponDependencyDesc spon_chunk_%d_dependencies[];\n", i))
  end

  c:write([[

typedef struct {
  uint32_t first;
  uint32_t count;
  const SponStencilDesc *stencils;
  const unsigned char *data;
  const SponEndpointDesc *endpoints;
  const SponLocationDesc *locations;
  const SponDataReloc *data_relocs;
  const SponControlReloc *control_relocs;
  const SponSlotMapEntry *slotmaps;
  const SponProjectionEntry *projections;
  const SponDependencyDesc *dependencies;
} SponBankShard;

]])

  c:write("static const SponBankShard spon_shards[] = {\n")
  for _, s in ipairs(shards) do
    local i = s.chunk
    c:write(string.format("  {%d, %d, spon_chunk_%d_stencils, spon_chunk_%d_data, spon_chunk_%d_endpoints, spon_chunk_%d_locations, spon_chunk_%d_data_relocs, spon_chunk_%d_control_relocs, spon_chunk_%d_slotmaps, spon_chunk_%d_projections, spon_chunk_%d_dependencies},\n",
      s.first, s.count, i, i, i, i, i, i, i, i, i))
  end
  c:write("};\n")
  c:write(string.format("static const uint32_t spon_shard_count = %d;\n", #shards))
  c:write(string.format("static const uint32_t spon_stencil_count = %d;\n\n", total_stencils))

  c:write("static const SponStencilId spon_l0[256] = {\n")
  for i = 0, 255 do
    if i % 8 == 0 then c:write("  ") end
    c:write(tostring(l0[i] or 0))
    if i ~= 255 then c:write(", ") end
    if i % 8 == 7 then c:write("\n") end
  end
  c:write("};\n\n")

  c:write("typedef struct { uint64_t pattern_key; uint32_t start; uint32_t count; } PatternEntry;\n")
  c:write("static const SponStencilId spon_candidates[] = {\n")
  local candidate_count = 0
  for _, k in ipairs(pattern_keys) do
    local list = patterns[k]
    table.sort(list, function(a, b) return a > b end)
    for _, packed in ipairs(list) do
      local id = math.floor(packed % U32)
      if candidate_count % 12 == 0 then c:write("  ") end
      c:write(tostring(id), ", ")
      candidate_count = candidate_count + 1
      if candidate_count % 12 == 0 then c:write("\n") end
    end
  end
  if candidate_count % 12 ~= 0 then c:write("\n") end
  c:write("};\n")

  c:write("static const PatternEntry spon_patterns[] = {\n")
  local start = 0
  for _, k in ipairs(pattern_keys) do
    local list = patterns[k]
    local len = math.floor(k / U32)
    local packed = math.floor(k - len * U32)
    c:write(string.format("  {0x%x%08xULL, %d, %d},\n", len, packed, start, #list))
    start = start + #list
  end
  c:write("};\n")
  c:write(string.format("static const uint32_t spon_pattern_count = %d;\n\n", #pattern_keys))

  c:write([[
static const SponBankShard *find_shard(SponStencilId id) {
  uint32_t lo = 0, hi = spon_shard_count;
  while (lo < hi) {
    uint32_t mid = lo + ((hi - lo) >> 1);
    const SponBankShard *s = &spon_shards[mid];
    if (id < s->first) hi = mid;
    else if (id >= s->first + s->count) lo = mid + 1;
    else return s;
  }
  return NULL;
}

static const PatternEntry *find_pattern(uint64_t key) {
  uint32_t lo = 0, hi = spon_pattern_count;
  while (lo < hi) {
    uint32_t mid = lo + ((hi - lo) >> 1);
    uint64_t mk = spon_patterns[mid].pattern_key;
    if (mk == key) return &spon_patterns[mid];
    if (mk < key) lo = mid + 1; else hi = mid;
  }
  return NULL;
}

static uint64_t make_pattern_key(const uint32_t *bc, uint32_t pc, uint32_t len) {
  uint32_t packed = 0;
  for (uint32_t i = 0; i < len; i++) packed |= ((bc[pc + i] & 0xffu) << (i * 8));
  return (((uint64_t)len) << 32) | (uint64_t)packed;
}

uint32_t spon_bank_stencil_count(void) { return spon_stencil_count; }
uint32_t spon_bank_pattern_count(void) { return spon_pattern_count; }

const SponStencilDesc *spon_get_stencil(SponStencilId id) {
  const SponBankShard *s = find_shard(id);
  if (!s) return NULL;
  return &s->stencils[id - s->first];
}

const unsigned char *spon_stencil_data(SponStencilId id) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->size == 0) return NULL;
  return s->data + f->offset;
}

const SponEndpointDesc *spon_stencil_endpoints(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_endpoints == 0) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = f->n_endpoints;
  return s->endpoints + f->endpoint_start;
}

const SponLocationDesc *spon_stencil_locations(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_endpoints == 0) { if (out_n) *out_n = 0; return NULL; }
  uint32_t first = 0xffffffffu;
  uint32_t last = 0;
  const SponEndpointDesc *eps = s->endpoints + f->endpoint_start;
  for (uint32_t i = 0; i < f->n_endpoints; i++) {
    if (eps[i].n_locations == 0) continue;
    if (eps[i].location_start < first) first = eps[i].location_start;
    if (eps[i].location_start + eps[i].n_locations > last) last = eps[i].location_start + eps[i].n_locations;
  }
  if (first == 0xffffffffu || last <= first) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = last - first;
  return s->locations + first;
}

const SponDataReloc *spon_stencil_data_relocs(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_data_relocs == 0) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = f->n_data_relocs;
  return s->data_relocs + f->data_reloc_start;
}

const SponControlReloc *spon_stencil_control_relocs(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_control_relocs == 0) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = f->n_control_relocs;
  return s->control_relocs + f->control_reloc_start;
}

const SponSlotMapEntry *spon_stencil_slotmaps(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_slotmaps == 0) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = f->n_slotmaps;
  return s->slotmaps + f->slotmap_start;
}

const SponProjectionEntry *spon_stencil_projections(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_projections == 0) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = f->n_projections;
  return s->projections + f->projection_start;
}

const SponDependencyDesc *spon_stencil_dependencies(SponStencilId id, uint32_t *out_n) {
  const SponBankShard *s = find_shard(id);
  const SponStencilDesc *f = spon_get_stencil(id);
  if (!s || !f || f->n_dependencies == 0) { if (out_n) *out_n = 0; return NULL; }
  if (out_n) *out_n = f->n_dependencies;
  return s->dependencies + f->dependency_start;
}

SponStencilId spon_l0_stencil_for_opcode(uint32_t opcode) {
  return opcode < 256 ? spon_l0[opcode] : 0;
}

static int actual_slot_lookup(const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots, uint16_t op_idx, uint8_t field_kind, uint8_t *out_slot) {
  for (uint32_t i = 0; i < n_actual_slots; i++) {
    if (actual_slots[i].op_idx == op_idx && actual_slots[i].field_kind == field_kind) { *out_slot = actual_slots[i].logical_slot; return 1; }
  }
  return 0;
}

static int stencil_matches_actual_slots(const SponStencilDesc *f, const SponBankShard *s, uint32_t pc, const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots) {
  if (!actual_slots) return 1;
  uint8_t logical_seen[256] = {0};
  uint8_t logical_to_actual[256] = {0};
  uint8_t actual_seen[256] = {0};
  uint8_t actual_to_logical[256] = {0};
  const SponSlotMapEntry *sms = s->slotmaps + f->slotmap_start;
  for (uint32_t i = 0; i < f->n_slotmaps; i++) {
    uint8_t actual = 0;
    uint8_t logical = sms[i].logical_slot;
    if (!actual_slot_lookup(actual_slots, n_actual_slots, (uint16_t)(pc + sms[i].op_idx), sms[i].field_kind, &actual)) return 0;
    if (actual >= 8) return 0;
    if (logical_seen[logical] && logical_to_actual[logical] != actual) return 0;
    logical_seen[logical] = 1;
    logical_to_actual[logical] = actual;
    if (actual_seen[actual] && actual_to_logical[actual] != logical) return 0;
    actual_seen[actual] = 1;
    actual_to_logical[actual] = logical;
  }
  return 1;
}

static SponFactSig remap_stencil_sig(const SponStencilDesc *f, const SponBankShard *s, SponFactSig sig, uint32_t pc, const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots) {
  if (!f || !actual_slots) return sig;
  uint8_t map[8] = {0};
  uint8_t seen[8] = {0};
  const SponSlotMapEntry *sms = s->slotmaps + f->slotmap_start;
  for (uint32_t i = 0; i < f->n_slotmaps; i++) {
    uint8_t logical = sms[i].logical_slot;
    uint8_t actual = 0;
    if (logical >= 8) continue;
    if (!actual_slot_lookup(actual_slots, n_actual_slots, (uint16_t)(pc + sms[i].op_idx), sms[i].field_kind, &actual)) continue;
    if (actual < 8) { seen[logical] = 1; map[logical] = actual; }
  }
  SponFactSig out = sig & 0x7f00000000000000ULL;
  static const uint8_t bases[] = {0,8,16,24,32,40,48};
  for (uint32_t bi = 0; bi < sizeof(bases); bi++) {
    uint8_t base = bases[bi];
    for (uint8_t slot = 0; slot < 8; slot++) {
      SponFactSig bit = ((SponFactSig)1) << (base + slot);
      if ((sig & bit) == 0) continue;
      uint8_t dst = seen[slot] ? map[slot] : slot;
      if (dst < 8) out |= ((SponFactSig)1) << (base + dst);
    }
  }
  return out;
}

static SponFactSig apply_transfer(SponFactSig facts, const SponStencilDesc *f, const SponBankShard *s, uint32_t pc, const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots) {
  if (!f) return facts;
  SponFactSig killed = remap_stencil_sig(f, s, f->killed_sig, pc, actual_slots, n_actual_slots);
  SponFactSig produced = remap_stencil_sig(f, s, f->produced_sig, pc, actual_slots, n_actual_slots);
  SponFactSig checked = remap_stencil_sig(f, s, f->checked_sig, pc, actual_slots, n_actual_slots);
  facts &= ~killed;
  facts |= produced;
  facts |= checked;
  return facts;
}

static const SponStencilChoice *select_flow_impl(const uint32_t *bc, uint32_t start, uint32_t end, SponFactSig entry_sig, SponFactSig observed_sig, uint16_t required_stencil_flags, const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots, uint32_t *out_n, SponSelectStats *stats) {
  static __thread SponStencilChoice choices[4096];
  uint32_t n = 0;
  uint32_t pc = start;
  uint64_t probes = 0, checks = 0;
  SponFactSig facts = entry_sig;
  while (pc < end && n < 4096) {
    SponStencilId chosen = 0;
    const SponStencilDesc *chosen_f = NULL;
    const SponBankShard *chosen_s = NULL;
    uint32_t chosen_len = 1;
    SponFactSig available_sig = observed_sig | facts;
    for (int len = 4; len >= 1; len--) {
      if (pc + (uint32_t)len > end) continue;
      probes++;
      const PatternEntry *pe = find_pattern(make_pattern_key(bc, pc, (uint32_t)len));
      if (!pe) continue;
      for (uint32_t i = 0; i < pe->count; i++) {
        checks++;
        SponStencilId fid = spon_candidates[pe->start + i];
        const SponBankShard *s = find_shard(fid);
        const SponStencilDesc *f = spon_get_stencil(fid);
        if (!s || !f) continue;
        if ((f->flags & required_stencil_flags) != required_stencil_flags) continue;
        if (!stencil_matches_actual_slots(f, s, pc, actual_slots, n_actual_slots)) continue;
        SponFactSig fsel = remap_stencil_sig(f, s, f->selector_sig, pc, actual_slots, n_actual_slots);
        SponFactSig freq = remap_stencil_sig(f, s, f->required_sig, pc, actual_slots, n_actual_slots);
        if (((fsel & ~available_sig) == 0) && ((freq & ~facts) == 0)) { chosen = fid; chosen_len = (uint32_t)len; chosen_f = f; chosen_s = s; break; }
      }
      if (chosen) break;
    }
    if (!chosen) {
      chosen = spon_l0_stencil_for_opcode(bc[pc] & 0xffu);
      chosen_f = spon_get_stencil(chosen);
      chosen_s = find_shard(chosen);
      chosen_len = 1;
      if (!chosen_f || ((chosen_f->flags & required_stencil_flags) != required_stencil_flags)) break;
    }
    choices[n].stencil_id = chosen;
    choices[n].pc_start = pc;
    choices[n].pc_end = pc + chosen_len;
    n++;
    facts = apply_transfer(facts, chosen_f, chosen_s, pc, actual_slots, n_actual_slots);
    pc += chosen_len;
  }
  if (out_n) *out_n = n;
  if (stats) { stats->pattern_probes = probes; stats->candidate_checks = checks; stats->choices = n; }
  return choices;
}

